def fibonacci(n: int) -> int:
    """Return the nth Fibonacci number."""
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b


def factorial(n: int) -> int:
    """Return n factorial."""
    if n < 0:
        raise ValueError("n must be non-negative")
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache: dict[str, Any] = {}
        self.order: list[str] = []

    def get(self, key: str) -> Any | None:
        if key not in self.cache:
            return None
        self.order.remove(key)
        self.order.append(key)
        return self.cache[key]

    def put(self, key: str, value: Any) -> None:
        if key in self.cache:
            self.order.remove(key)
        elif len(self.cache) >= self.capacity:
            oldest = self.order.pop(0)
            del self.cache[oldest]
        self.cache[key] = value
        self.order.append(key)

function debounce(fn, delay) {
  let timer = null;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

function throttle(fn, limit) {
  let inThrottle = false;
  return function (...args) {
    if (!inThrottle) {
      fn.apply(this, args);
      inThrottle = true;
      setTimeout(() => (inThrottle = false), limit);
    }
  };
}

use std::collections::HashMap;

pub struct TokenEstimator {
    code_patterns: Vec<regex::Regex>,
    bpt_code: f64,
    bpt_prose: f64,
}

impl TokenEstimator {
    pub fn new() -> Self {
        Self {
            code_patterns: vec![
                regex::Regex::new(r"(fn|let|mut|pub|impl|struct|enum)\s").unwrap(),
                regex::Regex::new(r"[{};]\s*$").unwrap(),
            ],
            bpt_code: 2.8,
            bpt_prose: 3.7,
        }
    }

    pub fn estimate(&self, text: &str) -> usize {
        let code_lines = text.lines()
            .filter(|l| self.code_patterns.iter().any(|p| p.is_match(l)))
            .count();
        let total_lines = text.lines().count().max(1);
        let code_ratio = code_lines as f64 / total_lines as f64;
        let bpt = self.bpt_code * code_ratio + self.bpt_prose * (1.0 - code_ratio);
        (text.len() as f64 / bpt).round() as usize
    }
}
